// ================================================================
// login.component.ts — Componente de Inicio de Sesión
// ================================================================
// Este componente maneja el formulario de login.
// Usa "Formularios Reactivos" de Angular, que son más poderosos
// que los formularios template porque permiten validaciones complejas
// y acceso programático desde el TypeScript.
//
// FLUJO COMPLETO DEL LOGIN:
// 1. Usuario escribe email y contraseña en el form HTML
// 2. Al hacer submit, llamamos a AuthService.login()
// 3. AuthService hace POST a /api/auth/login en el backend .NET
// 4. El backend verifica BCrypt y devuelve un JWT Token
// 5. AuthService guarda el token en localStorage
// 6. Redirigimos al usuario a /canchas
// ================================================================
import { Component } from '@angular/core';
import { FormBuilder, FormGroup, Validators } from '@angular/forms';
import { Router } from '@angular/router';
import { AuthService } from '../../../services/auth.service';

@Component({
  selector: 'app-login',
  templateUrl: './login.component.html',
  styleUrls: ['./login.component.css']
})
export class LoginComponent {

  // ============================================================
  // PROPIEDADES DEL COMPONENTE
  // ============================================================

  // FormGroup: es el objeto que representa TODO el formulario.
  // Contiene cada campo (FormControl) con sus valores y estado de validación.
  loginForm: FormGroup;

  // Controla si se muestra el spinner de carga mientras espera al backend.
  // true = mostramos spinner y deshabilitamos el botón.
  isLoading: boolean = false;

  // Mensaje de error para mostrar al usuario si el login falla.
  // Ejemplo: "Credenciales inválidas" o "Error de conexión".
  errorMessage: string = '';

  // Controla si la contraseña es visible (ojo abierto) o no (ojo cerrado).
  // false = contraseña oculta (tipo="password"), true = visible (tipo="text")
  showPassword: boolean = false;

  // Constructor: Angular inyecta automáticamente estos servicios.
  // FormBuilder: utilidad para crear formularios reactivos fácilmente.
  // AuthService: nuestro servicio que llama a la API.
  // Router: para navegar a otra página después del login exitoso.
  constructor(
    private fb: FormBuilder,
    private authService: AuthService,
    private router: Router
  ) {
    // ============================================================
    // DEFINICIÓN DEL FORMULARIO REACTIVO
    // ============================================================
    // fb.group() crea el FormGroup con sus campos y validadores.
    // Cada campo es un array: [valorInicial, [validadores...]]
    this.loginForm = this.fb.group({
      // Campo email:
      // - Valor inicial vacío: ''
      // - Validators.required: no puede estar vacío
      // - Validators.email: debe tener formato de email (con @ y dominio)
      email: ['', [Validators.required, Validators.email]],

      // Campo contraseña:
      // - Valor inicial vacío: ''
      // - Validators.required: no puede estar vacío
      password: ['', Validators.required]
    });
  }

  // ============================================================
  // GETTER: Acceso rápido a los campos del formulario
  // ============================================================
  // Los "getters" nos evitan escribir: this.loginForm.get('email')
  // cada vez que queremos verificar si un campo tiene error.
  // En el HTML podemos usar simplemente: f.email.invalid
  get f() {
    return this.loginForm.controls;
  }

  // ============================================================
  // TOGGLE DE VISIBILIDAD DE CONTRASEÑA
  // ============================================================
  // Cuando el usuario hace clic en el ícono de ojo en el HTML,
  // este método invierte el estado: visible → oculto → visible...
  togglePassword() {
    this.showPassword = !this.showPassword;
  }

  // ============================================================
  // MÉTODO PRINCIPAL: onSubmit()
  // ============================================================
  // Angular llama a este método cuando el usuario hace submit al formulario
  // (presiona el botón o da Enter). Lo enlazamos en HTML con (ngSubmit).
  onSubmit() {

    // VALIDACIÓN PREVENTIVA:
    // Si el formulario tiene errores (campo vacío, email inválido, etc.),
    // NO enviamos nada al backend. "return" detiene la ejecución aquí.
    if (this.loginForm.invalid) return;

    // Limpiamos cualquier error anterior de intentos previos
    this.errorMessage = '';

    // Activamos el estado de carga para mostrar el spinner en el botón
    this.isLoading = true;

    // ============================================================
    // LLAMADA AL SERVICIO DE AUTENTICACIÓN
    // ============================================================
    // authService.login() envía un POST a /api/auth/login con { email, password }.
    // .subscribe() es como "escuchar la respuesta" — funciona así:
    //   - next: se ejecuta si todo salió bien (código HTTP 200)
    //   - error: se ejecuta si algo falló (código HTTP 401, 500, etc.)
    this.authService.login(this.loginForm.value).subscribe({
      next: () => {
        // ✅ LOGIN EXITOSO
        // El AuthService ya guardó el token en localStorage automáticamente
        // (gracias al operador tap() que pusimos en auth.service.ts).
        // Solo necesitamos redirigir al usuario a la pantalla de canchas.
        this.isLoading = false;
        this.router.navigate(['/canchas']);
      },
      error: (err) => {
        // ❌ LOGIN FALLIDO
        // Apagamos el spinner
        this.isLoading = false;
        // Mostramos el mensaje de error del backend, o uno genérico si no lo hay
        this.errorMessage = err.error?.mensaje || 'Credenciales incorrectas. Verifica tu email y contraseña.';
      }
    });
  }
}
<!-- ================================================================
     login.component.html — Formulario de Inicio de Sesión
     ================================================================
     Este formulario usa la sintaxis de "Formularios Reactivos" de Angular.
     La diferencia clave con los formularios normales de HTML:
     - [formGroup]="loginForm" → conecta el HTML con el FormGroup del .ts
     - formControlName="email" → conecta este input con el FormControl "email"
     - (ngSubmit)="onSubmit()" → llama al método cuando el usuario hace submit
     ================================================================ -->

<!-- Página centrada con altura mínima de pantalla completa -->
<div class="auth-page">

  <!-- TARJETA DEL FORMULARIO DE LOGIN -->
  <div class="auth-card fade-in-up">

    <!-- ============================================================
         ENCABEZADO DE LA TARJETA
         ============================================================ -->
    <div class="auth-header">
      <!-- Ícono grande decorativo -->
      <div class="auth-icon-wrapper">
        <i class="bi bi-person-circle"></i>
      </div>
      <h1 class="auth-title">Bienvenido</h1>
      <p class="auth-subtitle">Ingresa a tu cuenta para continuar</p>
    </div>

    <!-- ============================================================
         ALERTA DE ERROR
         ============================================================
         *ngIf="errorMessage" hace que esta alerta solo aparezca
         cuando hay un mensaje de error que mostrar.
         Es invisible cuando errorMessage está vacío.
         ============================================================ -->
    <div class="alert alert-danger" *ngIf="errorMessage" role="alert" id="login-error-alert">
      <i class="bi bi-exclamation-triangle-fill me-2"></i>
      {{ errorMessage }}
    </div>

    <!-- ============================================================
         FORMULARIO REACTIVO
         ============================================================
         [formGroup]="loginForm" conecta este <form> con el FormGroup
         que definimos en login.component.ts.
         (ngSubmit)="onSubmit()" llama al método onSubmit() al hacer submit.
         ============================================================ -->
    <form [formGroup]="loginForm" (ngSubmit)="onSubmit()">

      <!-- ==================== CAMPO EMAIL ==================== -->
      <div class="mb-4">
        <label for="login-email" class="form-label">
          <i class="bi bi-envelope me-2"></i>Correo Electrónico
        </label>

        <!-- formControlName="email" enlaza este input con el control "email" del FormGroup -->
        <!-- [class.is-invalid] aplica la clase is-invalid de Bootstrap cuando el campo tiene errores
             Y el usuario ya lo tocó (f.email.touched) — evita mostrar error antes de que el user interactúe -->
        <input type="email"
               class="form-control"
               id="login-email"
               formControlName="email"
               [class.is-invalid]="f['email'].invalid && f['email'].touched"
               placeholder="admin@canchas.com"
               autocomplete="email">

        <!-- Mensajes de error de validación — solo aparecen cuando el campo fue tocado -->
        <div class="invalid-feedback" *ngIf="f['email'].touched && f['email'].errors">
          <!-- Si el error es 'required' (campo vacío) -->
          <span *ngIf="f['email'].errors?.['required']">
            <i class="bi bi-exclamation-circle me-1"></i>El email es obligatorio
          </span>
          <!-- Si el error es 'email' (formato incorrecto, sin @, sin dominio, etc.) -->
          <span *ngIf="f['email'].errors?.['email']">
            <i class="bi bi-exclamation-circle me-1"></i>Escribe un email válido (ej: usuario@correo.com)
          </span>
        </div>
      </div><!-- fin campo email -->

      <!-- ==================== CAMPO CONTRASEÑA ==================== -->
      <div class="mb-4">
        <label for="login-password" class="form-label">
          <i class="bi bi-lock me-2"></i>Contraseña
        </label>

        <!-- Wrapper para el ícono de "mostrar/ocultar contraseña" -->
        <div class="input-password-wrapper">
          <!-- El tipo del input cambia: 'text' = visible, 'password' = oculta -->
          <input [type]="showPassword ? 'text' : 'password'"
                 class="form-control"
                 id="login-password"
                 formControlName="password"
                 [class.is-invalid]="f['password'].invalid && f['password'].touched"
                 placeholder="Tu contraseña"
                 autocomplete="current-password">

          <!-- Botón de ojo para mostrar/ocultar contraseña -->
          <!-- (click)="togglePassword()" llama al método que cambia showPassword -->
          <!-- type="button" evita que este botón haga submit del formulario -->
          <button type="button"
                  class="password-toggle"
                  (click)="togglePassword()"
                  id="btn-toggle-password">
            <!-- Cambia el ícono según si la contraseña es visible o no -->
            <i class="bi" [class.bi-eye]="!showPassword" [class.bi-eye-slash]="showPassword"></i>
          </button>
        </div>

        <!-- Mensaje de error para contraseña vacía -->
        <div class="invalid-feedback" *ngIf="f['password'].touched && f['password'].errors">
          <span *ngIf="f['password'].errors?.['required']">
            <i class="bi bi-exclamation-circle me-1"></i>La contraseña es obligatoria
          </span>
        </div>
      </div><!-- fin campo contraseña -->

      <!-- ==================== BOTÓN DE SUBMIT ==================== -->
      <!-- [disabled]="loginForm.invalid || isLoading" deshabilita el botón si:
           - El formulario tiene errores de validación, O
           - Estamos esperando la respuesta del backend (isLoading = true) -->
      <button type="submit"
              class="btn btn-success w-100 btn-auth-submit"
              [disabled]="loginForm.invalid || isLoading"
              id="btn-login-submit">
        <!-- Spinner de carga que aparece mientras esperamos la respuesta del backend -->
        <span *ngIf="isLoading" class="spinner-border spinner-border-sm me-2" role="status"></span>
        <!-- Ícono normal cuando no está cargando -->
        <i class="bi bi-box-arrow-in-right me-2" *ngIf="!isLoading"></i>
        <!-- El texto también cambia -->
        {{ isLoading ? 'Verificando...' : 'Iniciar Sesión' }}
      </button>

    </form><!-- fin form -->

    <!-- ============================================================
         PIE DE TARJETA — Enlace al registro
         ============================================================ -->
    <div class="auth-footer">
      <p class="mb-0">
        ¿No tienes cuenta?
        <!-- [routerLink] es la forma de Angular de navegar sin recargar la página -->
        <a [routerLink]="['/register']" class="auth-link" id="link-ir-registro">
          Regístrate aquí
        </a>
      </p>
    </div>

    <!-- Divider y datos de prueba para facilitar las demos -->
    <div class="demo-credentials">
      <div class="demo-divider">
        <span>Datos de prueba</span>
      </div>
      <div class="demo-row">
        <div class="demo-item">
          <span class="demo-role admin">Admin</span>
          <code>admin@canchas.com</code>
          <code>admin123</code>
        </div>
        <div class="demo-item">
          <span class="demo-role cliente">Cliente</span>
          <code>cliente@canchas.com</code>
          <code>cliente123</code>
        </div>
      </div>
    </div>

  </div><!-- fin auth-card -->
</div><!-- fin auth-page -->
